package com.oyuki.kyc.entity; import com.oyuki.kyc.enums.KycStatus; import com.oyuki.user.entity.User; import jakarta.persistence.*; import lombok.*; import java.time.LocalDateTime; @Entity @Table(name="kyc_submissions") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class KycSubmission { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @OneToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="user_id",unique=true) private User user; @Column(nullable=false,length=50) private String idType; @Column(nullable=false,length=100) private String idNumber; @Column(nullable=false,length=500) private String documentUrl; @Column(length=500) private String selfieUrl; @Enumerated(EnumType.STRING) @Column(nullable=false,length=30) @Builder.Default private KycStatus status=KycStatus.PENDING; @Column(length=1000) private String reviewNote; private LocalDateTime submittedAt; private LocalDateTime reviewedAt; @PrePersist void create(){submittedAt=LocalDateTime.now();} }